Here's a ROS2 publisher node for publishing joint states of a 6-DOF arm using the joint_state_publisher package:

```cpp
#include <rclcpp/rclcpp.hpp>
#include <sensor_msgs/msg/joint_state.hpp>
#include <chrono>

using namespace std::chrono_literals;

class JointStatePublisher : public rclcpp::Node {
public:
    JointStatePublisher() : Node("joint_state_publisher") {
        publisher_ = this->create_publisher<sensor_msgs::msg::JointState>("joint_states", 10);
        timer_ = this->create_wall_timer(
            20ms, std::bind(&JointStatePublisher::timer_callback, this));

        // Initialize joint names for 6-DOF arm
        joint_names_ = {"joint1", "joint2", "joint3", "joint4", "joint5", "joint6"};
        position_.resize(6, 0.0);
        velocity_.resize(6, 0.0);
        effort_.resize(6, 0.0);
    }

private:
    void timer_callback() {
        auto message = sensor_msgs::msg::JointState();
        message.header.stamp = this->now();
        message.name = joint_names_;
        message.position = position_;
        message.velocity = velocity_;
        message.effort = effort_;

        // Simulate some movement (sinusoidal motion)
        auto now = this->now();
        double time_sec = now.seconds();
        for (size_t i = 0; i < position_.size(); ++i) {
            position_[i] = 0.5 * sin(0.5 * time_sec + i);
            velocity_[i] = 0.5 * 0.5 * cos(0.5 * time_sec + i);
        }

        publisher_->publish(message);
    }

    rclcpp::Publisher<sensor_msgs::msg::JointState>::SharedPtr publisher_;
    rclcpp::TimerBase::SharedPtr timer_;
    std::vector<std::string> joint_names_;
    std::vector<double> position_;
    std::vector<double> velocity_;
    std::vector<double> effort_;
};

int main(int argc, char * argv[])
{
    rclcpp::init(argc, argv);
    rclcpp::spin(std::make_shared<JointStatePublisher>());
    rclcpp::shutdown();
    return 0;
}
```

Key points:
1. Uses `sensor_msgs/msg/JointState` message type
2. Publishes at 50Hz (20ms period)
3. Includes header with timestamp
4. Simulates sinusoidal joint motion for demonstration
5. Properly initializes all joint state fields (position, velocity, effort)

For a real robot, you would replace the simulated joint values with actual sensor readings from encoders or motor controllers.

